package com.google.gson.interceptors;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.annotation.Annotation;

public class InterceptorFactoryTest {

  private InterceptorFactory interceptorFactory;

  @BeforeEach
  public void setUp() {
    interceptorFactory = new InterceptorFactory();
  }

  @Test
  public void create_shouldReturnNull_whenNoInterceptAnnotation() {
    // Arrange
    Gson gson = mock(Gson.class);
    TypeToken<Object> typeToken = TypeToken.get(Object.class);

    // Act
    TypeAdapter<Object> adapter = interceptorFactory.create(gson, typeToken);

    // Assert
    assertNull(adapter);
  }

  @Test
  public void create_shouldReturnInterceptorAdapter_whenInterceptAnnotationPresent() {
    // Arrange
    Gson gson = mock(Gson.class);
    @InterceptMock
    class AnnotatedClass {}

    TypeToken<AnnotatedClass> typeToken = TypeToken.get(AnnotatedClass.class);

    @SuppressWarnings("unchecked")
    TypeAdapter<AnnotatedClass> delegateAdapter = mock(TypeAdapter.class);

    when(gson.getDelegateAdapter(interceptorFactory, typeToken)).thenReturn(delegateAdapter);

    // Act
    TypeAdapter<AnnotatedClass> adapter = interceptorFactory.create(gson, typeToken);

    // Assert
    assertNotNull(adapter);
    assertNotSame(delegateAdapter, adapter);
    assertEquals("com.google.gson.interceptors.InterceptorAdapter", adapter.getClass().getName());
  }

  @Intercept
  private @interface InterceptMock {
  }
}
